<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand Sandbox</title>
<style>
  body{margin:0;background:#222;color:#eee;font-family:sans-serif;display:flex;flex-direction:column;align-items:center;}
  #controls{margin-top:10px;}
  button{background:#444;border:none;padding:6px 12px;margin:2px;color:#fff;border-radius:4px;cursor:pointer;}
  button:hover{background:#555;}
  canvas{border:1px solid #555;background:#111;}
</style>
</head>
<body>
<canvas id="sand" width="400" height="400"></canvas>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>

<script>
(() => {
  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d');
  const cellSize = 5; // 400/80
  const w = 80, h = 80;
  const grid = new Uint8Array(w*h); // 0 empty,1 sand,2 water,3 wall,4 acid

  const MATERIALS = {empty:0,sand:1,water:2,wall:3,acid:4};
  const COLORS = ['#111','#C69','#66F','#888','#0F0'];

  let currentMat = MATERIALS.sand;
  let painting = false;

  // API
  window.sim = {
    w,
    h,
    tick(n){ for(let i=0;i<n;i++) step(); render(); },
    get(x,y){ return Object.keys(MATERIALS).find(k=>MATERIALS[k]===grid[y*w+x]); },
    set(x,y,mat){ if(x<0||x>=w||y<0||y>=h)return; grid[y*w+x]=MATERIALS[mat]; },
    clear(){ grid.fill(0); render(); }
  };

  function step(){
    // process bottom-up
    for(let y=h-1;y>=0;y--){
      for(let x=0;x<w;x++){
        const idx = y*w+x;
        const cell = grid[idx];
        if(cell===MATERIALS.sand) moveSand(x,y);
        else if(cell===MATERIALS.water) moveWater(x,y);
        else if(cell===MATERIALS.acid) moveAcid(x,y);
      }
    }
  }

  function swap(a,b){ const tmp=grid[a]; grid[a]=grid[b]; grid[b]=tmp; }

  function moveSand(x,y){
    const below = (y+1<h)?(y+1)*w+x: -1;
    if(below>=0 && grid[below]===MATERIALS.empty) { swap(idx(x,y),below); return;}
    if(below>=0 && (grid[below]===MATERIALS.water||grid[below]===MATERIALS.acid)){
      swap(idx(x,y),below);
      return;
    }
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx=x+d, ny=y+1;
      if(nx>=0&&nx<w&&ny<h && grid[idx(nx,ny)]===MATERIALS.empty){
        swap(idx(x,y),idx(nx,ny));
        return;
      }
    }
  }

  function moveWater(x,y){
    const below = (y+1<h)?(y+1)*w+x: -1;
    if(below>=0 && grid[below]===MATERIALS.empty){ swap(idx(x,y),below); return;}
    // spread horizontally
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx=x+d, ny=y;
      if(nx>=0&&nx<w && grid[idx(nx,ny)]===MATERIALS.empty){
        swap(idx(x,y),idx(nx,ny));
        return;
      }
    }
  }

  function moveAcid(x,y){
    const below = (y+1<h)?(y+1)*w+x: -1;
    if(below>=0 && grid[below]===MATERIALS.empty){ swap(idx(x,y),below); return;}
    // dissolve below
    if(below>=0 && (grid[below]===MATERIALS.sand||grid[below]===MATERIALS.wall)){
      grid[idx(x,y)]=MATERIALS.empty;
      grid[below]=MATERIALS.empty;
      return;
    }
    // spread horizontally, dissolving adjacent
    const dirs = Math.random()<0.5?[-1,1]:[1,-1];
    for(const d of dirs){
      const nx=x+d, ny=y;
      if(nx>=0&&nx<w){
        const target=idx(nx,ny);
        if(grid[target]===MATERIALS.empty){ swap(idx(x,y),target); return;}
        if(grid[target]===MATERIALS.sand||grid[target]===MATERIALS.wall){
          grid[idx(x,y)]=MATERIALS.empty;
          grid[target]=MATERIALS.empty;
          return;
        }
      }
    }
  }

  function idx(x,y){return y*w+x;}

  function render(){
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let y=0;y<h;y++){
      for(let x=0;x<w;x++){
        const cell = grid[y*w+x];
        if(cell!==MATERIALS.empty){
          ctx.fillStyle=COLORS[cell];
          ctx.fillRect(x*cellSize,y*cellSize,cellSize,cellSize);
        }
      }
    }
  }

  // UI
  document.getElementById('mat-sand').onclick = ()=>currentMat=MATERIALS.sand;
  document.getElementById('mat-water').onclick = ()=>currentMat=MATERIALS.water;
  document.getElementById('mat-wall').onclick = ()=>currentMat=MATERIALS.wall;
  document.getElementById('mat-acid').onclick = ()=>currentMat=MATERIALS.acid;
  document.getElementById('mat-empty').onclick = ()=>currentMat=MATERIALS.empty;
  document.getElementById('clear').onclick = () => { window.sim.clear(); };

  canvas.addEventListener('mousedown', e=>{ painting=true; paint(e); });
  canvas.addEventListener('mousemove', e=>{ if(painting) paint(e); });
  canvas.addEventListener('mouseup', ()=>painting=false);
  canvas.addEventListener('mouseleave', ()=>painting=false);

  function paint(e){
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX - rect.left)/cellSize);
    const y = Math.floor((e.clientY - rect.top)/cellSize);
    if(x>=0&&x<w&&y>=0&&y<h) grid[y*w+x]=currentMat;
  }

  // Animation loop
  function loop(){ step(); render(); requestAnimationFrame(loop); }
  requestAnimationFrame(loop);

})();
</script>
</body>
</html>
